#include "Ast2Asg.hpp"
#include <unordered_map>

#define self (*this)

namespace asg {

// 符号表，保存当前作用域的所有声明
struct Ast2Asg::Symtbl : public std::unordered_map<std::string, Decl*>
{
  Ast2Asg& m;
  Symtbl* mPrev;

  Symtbl(Ast2Asg& m)
    : m(m)
    , mPrev(m.mSymtbl)
  {
    m.mSymtbl = this;
  }

  ~Symtbl() { m.mSymtbl = mPrev; }

  Decl* resolve(const std::string& name);
};

Decl*
Ast2Asg::Symtbl::resolve(const std::string& name)
{
  auto iter = find(name);
  if (iter != end())
    return iter->second;
  ASSERT(mPrev != nullptr); // 标识符未定义
  return mPrev->resolve(name);
}

TranslationUnit*
Ast2Asg::operator()(ast::TranslationUnitContext* ctx)
{
  auto ret = make<asg::TranslationUnit>();
  if (ctx == nullptr)
    return ret;

  Symtbl localDecls(self);

  for (auto&& i : ctx->externalDeclaration()) {
    if (auto p = i->declaration()) {
      auto decls = self(p);
      ret->decls.insert(ret->decls.end(),
                        std::make_move_iterator(decls.begin()),
                        std::make_move_iterator(decls.end()));
    }

    else if (auto p = i->functionDefinition()) {
      auto funcDecl = self(p);
      ret->decls.push_back(funcDecl);

      // 添加到声明表
      localDecls[funcDecl->name] = funcDecl;
    }

    else
      ABORT();
  }

  return ret;
}

//==============================================================================
// 类型
//==============================================================================

Ast2Asg::SpecQual
Ast2Asg::operator()(ast::DeclarationSpecifiersContext* ctx)
{
  SpecQual ret = { Type::Spec::kINVALID, Type::Qual() };

  for (auto&& i : ctx->declarationSpecifier()) {
    if (auto p = i->typeSpecifier()) {
      if (ret.first == Type::Spec::kINVALID) {
        if (p->Int())
          ret.first = Type::Spec::kInt;
        else
          ABORT(); // 未知的类型说明符
      }

      else
        ABORT(); // 未知的类型说明符
    }

    else
      ABORT();
  }

  return ret;
}

std::pair<TypeExpr*, std::string>
Ast2Asg::operator()(ast::DeclaratorContext* ctx, TypeExpr* sub)
{
  return self(ctx->directDeclarator(), sub);
}

static int
eval_arrlen(Expr* expr)
{
  if (auto p = expr->dcst<IntegerLiteral>())
    return p->val;

  if (auto p = expr->dcst<DeclRefExpr>()) {
    if (p->decl == nullptr)
      ABORT();

    auto var = p->decl->dcst<VarDecl>();
    if (!var || !var->type->qual.const_)
      ABORT(); // 数组长度必须是编译期常量

    switch (var->type->spec) {
      case Type::Spec::kChar:
      case Type::Spec::kInt:
      case Type::Spec::kLong:
      case Type::Spec::kLongLong:
        return eval_arrlen(var->init);

      default:
        ABORT(); // 长度表达式必须是数值类型
    }
  }

  if (auto p = expr->dcst<UnaryExpr>()) {
    auto sub = eval_arrlen(p->sub);

    switch (p->op) {
      case UnaryExpr::kPos:
        return sub;

      case UnaryExpr::kNeg:
        return -sub;

      default:
        ABORT();
    }
  }

  if (auto p = expr->dcst<BinaryExpr>()) {
    auto lft = eval_arrlen(p->lft);
    auto rht = eval_arrlen(p->rht);

    switch (p->op) {
      case BinaryExpr::kAdd:
        return lft + rht;

      case BinaryExpr::kSub:
        return lft - rht;

      default:
        ABORT();
    }
  }

  if (auto p = expr->dcst<InitListExpr>()) {
    if (p->list.empty())
      return 0;
    return eval_arrlen(p->list[0]);
  }

  ABORT();
}

std::pair<TypeExpr*, std::string>
Ast2Asg::operator()(ast::DirectDeclaratorContext* ctx, TypeExpr* sub)
{
  if (auto p = ctx->Identifier())
    return { sub, p->getText() };

  if (ctx->LeftBracket()) {
    auto arrayType = make<ArrayType>();
    arrayType->sub = sub;

    if (auto p = ctx->assignmentExpression())
      arrayType->len = eval_arrlen(self(p));
    else
      arrayType->len = ArrayType::kUnLen;

    return self(ctx->directDeclarator(), arrayType);
  }

  ABORT();
}

//==============================================================================
// 表达式
//==============================================================================

Expr*
Ast2Asg::operator()(ast::ExpressionContext* ctx)
{
  auto list = ctx->assignmentExpression();
  Expr* ret = self(list[0]);

  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kComma;
    node->lft = ret;
    node->rht = self(list[i]);
    ret = node;
  }

  return ret;
}

Expr*
Ast2Asg::operator()(ast::AssignmentExpressionContext* ctx)
{
  if (auto p = ctx->conditionalExpression())
    return self(p);

  auto ret = make<BinaryExpr>();
  ret->op = ret->kAssign;
  ret->lft = self(ctx->unaryExpression());
  ret->rht = self(ctx->assignmentExpression());
  return ret;
}
// Generic binary expression helper
static BinaryExpr::Op tokenToBinaryOp(size_t tokenType)
{
  switch (tokenType) {
    case ast::Plus: return BinaryExpr::kAdd;
    case ast::Minus: return BinaryExpr::kSub;
    case ast::Star: return BinaryExpr::kMul;
    case ast::Slash: return BinaryExpr::kDiv;
    case ast::Percent: return BinaryExpr::kMod;
    case ast::Less: return BinaryExpr::kLt;
    case ast::Greater: return BinaryExpr::kGt;
    case ast::LessEqual: return BinaryExpr::kLe;
    case ast::GreaterEqual: return BinaryExpr::kGe;
    case ast::EqualEqual: return BinaryExpr::kEq;
    case ast::NotEqual: return BinaryExpr::kNe;
    case ast::AndAnd: return BinaryExpr::kAnd;
    case ast::OrOr: return BinaryExpr::kOr;
    case ast::And: return BinaryExpr::kINVALID; // Bitwise AND
    case ast::Or: return BinaryExpr::kINVALID;  // Bitwise OR
    case ast::Xor: return BinaryExpr::kINVALID; // Bitwise XOR
    default: ABORT();
  }
}

template<typename Ctx>
Expr*
makeBinaryChain(Ast2Asg& ast2asg, Ctx* ctx, BinaryExpr::Op baseOp = BinaryExpr::kINVALID)
{
  auto children = ctx->children;
  auto first = dynamic_cast<decltype(ctx->castExpression(0))>(children[0]);
  (void)first;
  Expr* ret = ast2asg(dynamic_cast<decltype(ctx->castExpression(0))>(children[0]));

  for (unsigned i = 1; i; i < children.size(); ++i) {
    auto node = ast2asg.mMgr.template make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
                   ->getSymbol()->getType();
    auto op = tokenToBinaryOp(token);
    if (op == BinaryExpr::kINVALID) {
      // Handle bitwise ops
      if (token == ast::And) op = BinaryExpr::kINVALID; // We'll skip this
      else ABORT();
    }
    node->op = op;
    node->lft = ret;
    node->rht = ast2asg(dynamic_cast<decltype(ctx->castExpression(0))>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::AdditiveExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::MultiplicativeExpressionContext*>(children[0]));

  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])->getSymbol()->getType();
    switch (token) {
      case ast::Plus: node->op = node->kAdd; break;
      case ast::Minus: node->op = node->kSub; break;
      default: ABORT();
    }
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::MultiplicativeExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::MultiplicativeExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::CastExpressionContext*>(children[0]));

  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
                   ->getSymbol()->getType();
    switch (token) {
      case ast::Star: node->op = node->kMul; break;
      case ast::Slash: node->op = node->kDiv; break;
      case ast::Percent: node->op = node->kMod; break;
      default: ABORT();
    }
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::CastExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::RelationalExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::ShiftExpressionContext*>(children[0]));

  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
                   ->getSymbol()->getType();
    switch (token) {
      case ast::Less: node->op = node->kLt; break;
      case ast::Greater: node->op = node->kGt;kGt; break;
      case ast::LessEqual: node->op = node->;kLe; break;
      case ast::GreaterEqual: node->op = node->kGe; break;
      default: ABORT();
    }
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::ShiftExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::EqualityExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::RelationalExpressionContext*>(children[0]));

  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
                   ->getSymbol()->getType();
    switch (token) {
      case ast::EqualEqual: node->op = node->kEq; break;
      case ast::NotEqual: node->op = node->kNe; break;
      default: ABORT();
    }
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::RelationalExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::AndExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::EqualityExpressionContext*>(children[0]));
  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    // Bitwise AND - not directly supported in our asg, skip for now
    node->op = node->kINVALID;
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::EqualityExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::ExclusiveOrExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::AndExpressionContext*>(children[0]));
  for (unsigned i = 1; i < children.size(); i += 2) {
    auto node = make<BinaryExpr>();
    node->op = node->kINVALID;
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::AndExpressionContext*>(children[i + 1]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::InclusiveOrExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::ExclusiveOrExpressionContext*>(children[0]));
  for (unsigned i = 1; i < children.size(); i += 2) {
    auto node = make<BinaryExpr>();
    node->op = node->kINVALID;
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::ExclusiveOrExpressionContext*>(children[i + 1]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::LogicalAndExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::InclusiveOrExpressionContext*OrExpressionContext*>(children[0]));
  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kAnd;
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::InclusiveOrExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::LogicalOrExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::LogicalAndExpressionContext*>(children[0]));
  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kOr;
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::LogicalAndExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::ConditionalExpressionContext* ctx)
{
  return self(ctx->logicalOrExpression());
}

Expr*
Ast2Asg::operator()(ast::ShiftExpressionContext* ctx)
{
  return self(dynamic_cast<ast::AdditiveExpressionContext*>(ctx->children[0]));
}

Expr*
Ast2Asg::operator()(ast::UnaryExpressionContext* ctx)
{
  if (auto p = ctx->postfixExpression())
    return self(p);

  auto ret = make<UnaryExpr>();

  // Handle unaryOperator
  if (auto op = ctx->unaryOperator()) {
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(op->children[0])
                   ->getSymbol()->getType();
    switch (token) {
      case ast::Plus: ret->op = ret->kPos; break;
      case ast::Minus: ret->op = ret->kNeg; break;
      case ast::Not: ret->op = ret->kNot; break;
      case ast::Star: // Dereference - not handled yet
      case ast::And: // Address-of - not handled yet
      default: break;
    }
    ret->sub = self(ctx->unaryExpression());
    return ret;
  }

  ABORT();
}

Expr*
Ast2Asg::operator()(ast::PostfixExpressionContext* ctx)
{
  auto children = ctx->children;
  auto sub = self(dynamic_cast<ast::PrimaryExpressionContext*>(children[0]));

  // Handle postfix operators like function calls and array indexing
  for (unsigned i = 1; i < children.size(); ++i) {
    if (auto paren = dynamic_cast<ast::LeftParenContext*>(children[i])) {
      // Function call
      auto call = make<CallExpr>();
      call->head = sub;
      // Parse arguments if present
      if (i + 1 < children.size()) {
        auto argCtx = dynamic_cast<ast::ArgumentExpressionListContext*>(children[i + 1]);
        if (argCtx) {
          for (auto&& expr : argCtx->assignmentExpression())
            call->args.push_back(self(expr));
          ++i;
        }
      }
      // Skip RightParen
      ++i;
      sub = call;
    } else if (auto bracket = dynamic_cast<ast::LeftBracketContext*>(children[i])) {
      // Array subscript
      auto index = make<BinaryExpr>();
      index->op = index->kIndex;
      index->lft = sub;
      index->rht = self(dynamic_cast<ast::ExpressionContext*>(children[i + 1]));
      ++i; // Skip expression
      ++i; // Skip RightBracket
      sub = index;
    }
  }
  return sub;
}

Expr*
Ast2Asg::operator()(ast::PrimaryExpressionContext* ctx)
{
  if (auto p = ctx->Identifier()) {
    auto name = p->getText();
    auto ret = make<DeclRefExpr>();
    ret->decl = mSymtbl->resolve(name);
    return ret;
  }

  if (auto p = ctx->Constant()) {
    auto text = p->getText();
    auto ret = make<IntegerLiteral>();
    ASSERT(!text.empty());
    if (text[0] != '0')
      ret->val = std::stoll(text);
    else if (text.size() == 1)
      ret->val = 0;
    else if (text[1] == 'x' || text[1] == 'X')
      ret->val = std::stoll(text.substr(2), nullptr, 16);
    else
      ret->val = std::stoll(text.substr(1), nullptr, 8);
    return ret;
  }

  if (auto p = ctx->expression()) {
    auto ret = make<ParenExpr>();
    ret->sub = self(p);
    return ret;
  }

  ABORT();
}

Expr*
Ast2Asg::operator()(ast::InitializerContext* ctx)
{
  if (auto p = ctx->assignmentExpression())
    return self(p);

  auto ret = make<InitListExpr>();
  if (auto p = ctx->initializerList()) {
    for (auto&& i : p->initializer()) {
      auto expr = self(i);
      if (auto p = expr->dcst<InitListExpr>()) {
        for (auto&& sub : p->list)
          ret->list.push_back(sub);
      } else {
        ret->list.push_back(expr);
      }
    }
  }
  return ret;
}

//==============================================================================
// 语句
//==============================================================================

Stmt*
Ast2Asg::operator()(ast::StatementContext* ctx)
{
  if (auto p = ctx->compoundStatement())
    return self(p);

  if (auto p = ctx->expressionStatement())
    return self(p);

  if (auto p = ctx->jumpStatement())
    return self(p);

  ABORT();
}

CompoundStmt*
Ast2Asg::operator()(ast::CompoundStatementContext* ctx)
{
  auto ret = make<CompoundStmt>();

  if (auto p = ctx->blockItemList()) {
    Symtbl localDecls(self);

    for (auto&& i : p->blockItem()) {
      if (auto q = i->declaration()) {
        auto sub = make<DeclStmt>();
        sub->decls = self(q);
        ret->subs.push_back(sub);
      }

      else if (auto q = i->statement())
        ret->subs.push_back(self(q));

      else
        ABORT();
    }
  }

  return ret;
}

Stmt*
Ast2Asg::operator()(ast::ExpressionStatementContext* ctx)
{
  if (auto p = ctx->expression()) {
    auto ret = make<ExprStmt>();
    ret->expr = self(p);
    return ret;
  }

  return make<NullStmt>();
}

Stmt*
Ast2Asg::operator()(ast::JumpStatementContext* ctx)
{
  if (ctx->Return()) {
    auto ret = make<ReturnStmt>();
    ret->func = mCurrentFunc;
    if (auto p = ctx->expression())
      ret->expr = self(p);
    return ret;
  }

  ABORT();
}

//==============================================================================
// 声明
//==============================================================================

std::vector<Decl*>
Ast2Asg::operator()(ast::DeclarationContext* ctx)
{
  std::vector<Decl*> ret;

  auto specs = self(ctx->declarationSpecifiers());

  if (auto p = ctx->initDeclaratorList()) {
    for (auto&& j : p->initDeclarator())
      ret.push_back(self(j, specs));
  }

  // 如果 initDeclaratorList 为空则这行声明语句无意义
  return ret;
}

FunctionDecl*
Ast2Asg::operator()(ast::FunctionDefinitionContext* ctx)
{
  auto ret = make<FunctionDecl>();
  mCurrentFunc = ret;

  auto type = make<Type>();
  ret->type = type;

  auto sq = self(ctx->declarationSpecifiers());
  type->spec = sq.first, type->qual = sq.second;

  auto [texp, name] = self(ctx->declarator(), nullptr);
  auto funcType = make<FunctionType>();
  funcType->sub = texp;
  type->texp = funcType;
  funcType;
  ret->name = std::move(name);

  Symtbl localDecls(self);

  // 函数定义在签名之后就加入符号表，以允许递归调用
  (*mSymtbl)[ret->name] = ret;

  ret->body = self(ctx->compoundStatement());

  return ret;
}

Decl*
Ast2Asg::operator()(ast::InitDeclaratorContext* ctx, SpecQual sq)
{
  auto [texp, name] = self(ctx->declarator(), nullptr);
  Decl* ret;

  if (auto funcType = texp->dcst<FunctionType>()) {
    auto fdecl = make<FunctionDecl>();
    auto type = make<Type>();
    fdecl->type = type;

    type->spec = sq.first;
    type->qual = sq.second;
    type->texp = funcType;

    fdecl->name = std::move(name);
    for (auto p : funcType->params) {
      auto paramDecl = make<VarDecl>();
      paramDecl->type = p;
      fdecl->params.push_back(paramDecl);
    }

    if (ctx->initializer())
      ABORT();
    fdecl->body = nullptr;

    ret = fdecl;
  }

  else {
    auto vdecl = make<VarDecl>();
    auto type = make<Type>();
    vdecl->type = type;

    type->spec = sq.first;
    type->qual = sq.second;
    type->texp = texp;
    vdecl->name = std::move(name);

    if (auto p = ctx->initializer())
      vdecl->init = self(p);
    else
      vdecl->init = nullptr;

    ret = vdecl;
  }

  // 这个实现允许符号重复定义，新定义会取代旧定义
  (*mSymtbl)[ret->name] = ret;
  return ret;
}

} // namespace asg
